    def query_group_list(self, group_type: str = "all", env_name="Default", group_name=None) -> list:
        """分组列表查询（私有/公共分组）
        :param group_type: one of ["all", "private", "public"]
        :param env_name: 环境名
        :return:  list of
        {
                "app_id": "xxxx-xxx-xxxx-xxxx-xxxx-xxxx",
                "create_time": "2019-11-25 15:58:37",
                "description": "",
                "group_id": 75,
                "group_name": "prod.sh",
                "group_type": "PRIVATE",
                "permission_type": "PERMISSION_NONE"
            },
        """

        path = "/adminapi.Config/QueryGroupListReq"
        payload = {"app_id": self.app_id, "env_name": env_name}
        if group_type == "private":
            payload["group_type"] = 1
        elif group_type == "public":
            payload["group_type"] = 2
        # 查询指定分组名的详情
        if group_name:
            payload["group_name"] = group_name
        return self._send(path, payload)["group_infos"]

