    def change_group(
        self,
        group_id,
        group_name,
        description=None,
        is_public=False,
        op_type=0,
        config_type=0,
        omit_approval=0,
        model_type=0,
        keep_ver=0,
        multi_version=0,
        env_name="Default",
        publish_type="DEFAULT",
        disable_file_auth=False,
    ):
        """变更分组信息(增加/修改/删除)

        :param group_id:
        :param group_name:
        :param description:
        :param is_public:
        :param op_type: 1删除，2更新，3增加
        :param config_type: 0:KV, 1:TableGroup
        :param env_name:
        :param publish_type: DEFAULT or ZHIYAN
        :param model_type: 审批模式，0：默认，1：review
        :param omit_approval: 免审批，0：关闭，1：开启
        :param keep_ver: 保留的版本数
        :param multi_version: 多版本发布，0：关闭，1：开启
        :return:
        """
        path = "/adminapi.Config/ChangeGroupReq"
        payload = dict(
            app_id=self.app_id,
            group_id=group_id,
            group_name=group_name,
            description=description,
            group_type=2 if is_public else 1,
            op_type=op_type,
            config_type=config_type,
            omit_approval=int(omit_approval),
            model_type=model_type,
            keep_ver=keep_ver,
            multi_version=multi_version,
            env_name=env_name,
            publish_type=publish_type,
            disable_file_auth=disable_file_auth,
        )
        return self._send(path, payload)["group_info"]

    def change_group_setting(
        self,
        group_id,
        group_name,
        env_name='Default',
        **setting
    ):
        path = "/adminapi.Config/ChangeGroupReq"
        setting.update(dict(
            app_id=self.app_id,
            group_id=group_id,
            group_name=group_name,
            env_name=env_name
        ))
        return self._send(path, setting)['group_info']

