    def create_release_task(
        self,
        env_name,
        group_id,
        group_name,
        creator,
        approvers,
        type,
        version_name=None,
        multi_step_gray_contents=None,
        description="",
        updators=None,
    ) -> int:
        """创建发布任务（提交审批）"""
        path = "/adminapi.Config/CreateReleaseTaskReq"
        if not version_name:
            now = datetime.now().strftime("%Y%m%d%H%M%S%f")
            version_name = f"v_{now}_release"
        payload = {
            "app_id": self.app_id,
            "env_name": env_name,
            "group_id": group_id,
            "group_name": group_name,
            "creator": creator,
            "description": description,
            "version_name": version_name,
            "multi_step_gray_contents": multi_step_gray_contents,
            "approvers": approvers,
            "type": type,
            "updators": updators if updators else creator,
        }
        return self._send(path, payload)["task_id"]

