    def one_click_release_task(
        self,
        group_id,
        group_name,
        creator,
        updators,
        approvers,
        env_name,
        version_name=None,
        description="",
        coding_plugin=None,
    ):
        """一键发布任务
        doc: https://iwiki.woa.com/pages/viewpage.action?pageId=98145038
            # 一键发布任务
        """
        path = "/adminapi.Config/OneClickReleaseTaskReq"
        if not version_name:
            now = datetime.now().strftime("%Y%m%d%H%M%S%f")
            version_name = f"v_{now}_release"
        payload = {
            "app_id": self.app_id,
            "creator": creator,
            "group_id": group_id,
            "group_name": group_name,
            "description": description,
            "version_name": version_name,
            "updators": updators,
            "env_name": env_name,
            "approvers": approvers,
            "type": 0,
        }
        if coding_plugin == 2:
            payload.pop("type")
            payload.pop("approvers")
            payload['leave'] = json.dumps(dict(prod_change=coding_plugin, change_number=''))

        return self._send(path, payload)

