    def build_kv(
        self, key, value, group_id, value_type=2, description="", op_type=0, id_=None
    ):
        """
        :param id_:
        :param key:
        :param value:
        :param value_type: 1:NUMBER，2:STRING，3:TEXT，4:JSON，5:XML，18:日期, 20:YAML;
        :param description:
        :param group_id:
        :param op_type: KV数据操作类型(增加：2/修改：1/删除：3)
        :return:
        """
        kv = {
            "config_op_type": op_type,
            "group_id": group_id,
            "from_group_id": group_id,
            "key": key,
            "value": value,
            "value_type": value_type,
            "description": description,
        }
        if id_:
            kv["id"] = id_
        return kv

    def change_key(
        self, group_id, group_name, key_values, is_sync=False, common_version_id=0
    ):
        """修改配置key(增加/修改/删除)"""
        path = "/adminapi.Config/ChangeKeyReq"
        assert isinstance(key_values, list)
        payload = {
            "app_id": self.app_id,
            "change_group_id": group_id,
            "group_name": group_name,
            "key_values": key_values,
            "is_sync": is_sync,
        }
        if is_sync:
            payload["common_version_id"] = common_version_id
        return self._send(path, payload)["key_value"]

    def add_kv(self, group_id, group_name, key_values, is_sync=False):
        for i in key_values:
            i["config_op_type"] = 2
        return self.change_key(group_id, group_name, key_values, is_sync)

    def delete_key(self, group_id, group_name, key_values, is_sync=False):
        for i in key_values:
            i["config_op_type"] = 3
        return self.change_key(group_id, group_name, key_values, is_sync)

    def update_key(self, group_id, group_name, key_values, is_sync=False):
        for i in key_values:
            i["config_op_type"] = 1
        return self.change_key(group_id, group_name, key_values, is_sync)

