    """文件型配置"""

    def change_file_request(
        self,
        group_name,
        op_type,
        filename,
        file_reader=None,
        description="",
        need_uncompress=False,
        env_name="Default",
    ):
        """文件型配置增删改
        op_type: 1：新增 2：删除 3：更新 4：添加 or更新 5：覆盖更新"""
        path = "/adminapi.Config/ChangeFileReq"
        if file_reader:
            content = file_reader.read()
            if isinstance(content, str):
                content = content.encode("utf-8")
            encode = base64.b64encode(content).decode("utf-8")
        else:
            encode = ""
        payload = {
            "group_name": group_name,
            "app_id": self.app_id,
            "env_name": env_name,
            "info": {
                "name": filename,
                "description": description,
                "content": encode,
                "op_type": op_type,
                "need_uncompress": need_uncompress,
            },
        }
        return self._send(path, payload)

